@IgnoreJRERequirement // Only added when Optional is available (Java 8+ / Android API 24+).
@TargetApi(24)
public final class OptionalConverterFactory extends Converter.Factory {
  public static OptionalConverterFactory create() {
    return new OptionalConverterFactory();
  }

  OptionalConverterFactory() {}

  @Override
  public @Nullable Converter<ResponseBody, ?> responseBodyConverter(
      Type type, Annotation[] annotations, Retrofit retrofit) {
    if (getRawType(type) != Optional.class) {
      return null;
    }

    Type innerType = getParameterUpperBound(0, (ParameterizedType) type);
    Converter<ResponseBody, Object> delegate =
        retrofit.responseBodyConverter(innerType, annotations);
    return new OptionalConverter<>(delegate);
  }

  @IgnoreJRERequirement
  static final class OptionalConverter<T> implements Converter<ResponseBody, Optional<T>> {
    private final Converter<ResponseBody, T> delegate;

    OptionalConverter(Converter<ResponseBody, T> delegate) {
      this.delegate = delegate;
    }

    @Override
    public Optional<T> convert(ResponseBody value) throws IOException {
      return Optional.ofNullable(delegate.convert(value));
    }
  }
}

package com.alibaba.fastjson2.filter;

import com.alibaba.fastjson2.JSONWriter;

import java.util.ArrayList;
import java.util.List;

final class CompositePropertyPreFilter
        implements PropertyPreFilter {
    private final List<PropertyPreFilter> filters = new ArrayList<>();

    public CompositePropertyPreFilter(PropertyPreFilter... filters) {
        for (PropertyPreFilter filter : filters) {
            if (filter != null) {
                this.filters.add(filter);
            }
        }
    }

    public void add(PropertyPreFilter filter) {
        if (filter != null) {
            this.filters.add(filter);
        }
    }

    @Override
    public boolean process(JSONWriter writer, Object source, String name) {
        for (PropertyPreFilter filter : filters) {
            if (!filter.process(writer, source, name)) {
                return false;
            }
        }
        return true;
    }
}

package com.alibaba.fastjson2.filter;

import com.alibaba.fastjson2.PropertyNamingStrategy;
import com.alibaba.fastjson2.util.BeanUtils;

import java.util.function.Function;

public interface NameFilter
        extends Filter {
    String process(Object object, String name, Object value);

    static NameFilter of(PropertyNamingStrategy namingStrategy) {
        return (object, name, value) -> BeanUtils.fieldName(name, namingStrategy.name());
    }

    static NameFilter compose(NameFilter before, NameFilter after) {
        return (object, name, value) ->
                after.process(
                        object,
                        before.process(object, name, value),
                        value
                );
    }

    static NameFilter of(Function<String, String> function) {
        return (object, name, value) -> function.apply(name);
    }
}

